import collections

def read_last_n_lines(file_path: str, n: int) -> list[str]:
    if n <= 0:
        return []

    with open(file_path, 'r', encoding='utf-8') as f:
        last_n_lines = collections.deque(maxlen=n)
        for line in f:
            last_n_lines.append(line)
        return list(last_n_lines)
